from kafka import KafkaProducer
import json
from flask import Flask, request, jsonify

app = Flask(__name__)

def create_kafka_producer(kafka_bootstrap_servers):
    producer = KafkaProducer(bootstrap_servers=kafka_bootstrap_servers,
                             security_protocol='PLAINTEXT',
                             value_serializer=lambda x: json.dumps(x).encode('utf-8'))
    return producer

@app.route('/publish', methods=['POST'])
def publish_message():
    kafka_bootstrap_servers = 'localhost:9092'
    topic_name = request.args.get('topic')
    message = request.json['message']

    if not topic_name or not message:
        return jsonify({'error': 'Topic name and message are required'}), 400

    producer = create_kafka_producer(kafka_bootstrap_servers)
    try:
        producer.send(topic_name, message)
        return jsonify({'status': 'Message published successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500
    finally:
        producer.close()

if __name__ == '__main__':
    app.run(debug=True)